const data = $input.first().json;

const CONSULTATION_URL = $vars.CONSULTATION_URL || 'https://metabelly.com/kontakt';

const consultationNote = data.language === 'HR'
  ? `\n\nAko želite razgovarati s nama, kontaktirajte nas: ${CONSULTATION_URL}`
  : `\n\nIf you would like to speak with us, please contact us: ${CONSULTATION_URL}`;

let replyBody = data.auto_reply || '';

if (data.category === 'MEDICAL') {
  replyBody = data.language === 'HR'
    ? `Hvala vam na povjerenju i što ste nam se obratili.\n\nVaše pitanje zahtijeva savjet stručnjaka, stoga ćemo ga proslijediti timu koji će vam odgovoriti u najkraćem mogućem roku.\n\nZa brži odgovor: ${CONSULTATION_URL}`
    : `Thank you for reaching out to us.\n\nYour question requires expert advice and we will forward it to our team who will get back to you as soon as possible.\n\nFor a faster response: ${CONSULTATION_URL}`;
} else if (replyBody) {
  replyBody = replyBody + consultationNote;
}

return [{ json: { ...data, finalReply: replyBody } }];

